func expand_8_64(text []byte, freq, bucket, sa []int64, numLMS int) {
	bucketMax_8_64(text, freq, bucket)
	bucket = bucket[:256] // 消除下面 bucket[c] 的边界检查

	// 向后循环遍历 sa，始终跟踪
	// 接下来要从 sa[:numLMS] 填充的索引。
	// 当我们到达一个时，填充它。
	// 其余槽位置清零；它们里面有死值。
	x := numLMS - 1
	saX := sa[x]
	c := text[saX]
	b := bucket[c] - 1
	bucket[c] = b

	for i := len(sa) - 1; i >= 0; i-- {
		if i != int(b) {
			sa[i] = 0
			continue
		}
		sa[i] = saX

		// 加载下一个要放置的条目（如果有）。
		if x > 0 {
			x--
			saX = sa[x] // TODO 边界检查
			c = text[saX]
			b = bucket[c] - 1
			bucket[c] = b
		}
	}
}

